@prefix dcat: <http://www.w3.org/ns/dcat#> .
@prefix dct: <http://purl.org/dc/terms/> .
@prefix foaf: <http://xmlns.com/foaf/0.1/> .
@prefix qkg: <http://quotekg.org/resource/> .

qkg:QuoteKG
  a dcat:Dataset ;
  dct:title "QuoteKG"@en ;
  dct:description "QuoteKG is a large-scale multilingual knowledge graph of quotations, designed to capture and link quotes from public figures across different languages, contexts, and sources"@en ;
  dct:creator [
    foaf:name "Tin Kuculo" ;
    foaf:mbox <mailto:Tin@hotmail.com>;
  ], [
    foaf:name "Simon Gottschalk";
    foaf:mbox <mailto:simon@yahoo.com>;
  ] ;
  dcat:landingPage <https://github.com/tkuculo/QuoteKG> ;
  dct:license <https://creativecommons.org/licenses/by-sa/4.0/legalcode> .
